// HMAC-SHA256 Verification (R-003, R-014)
// Centralized sub-workflow — called by all webhook workflows
// Constitution II: Threat-model driven (unauthorized webhook callers)

const crypto = require('crypto');

const secret = $env.OPENCLAW_WEBHOOK_SECRET;
if (!secret) {
  return [{ json: { verified: false, error: 'OPENCLAW_WEBHOOK_SECRET not set in environment' } }];
}

// Read headers and body from the calling workflow's input
const inputData = $input.all()[0].json;
const signature = inputData.headers?.['x-signature'] || '';
const timestamp = inputData.headers?.['x-timestamp'] || '';
const rawBody = inputData.rawBody || JSON.stringify(inputData.body || {});

// Replay protection: timestamp must be within 5 minutes
const now = Math.floor(Date.now() / 1000);
const requestTime = parseInt(timestamp, 10);
if (isNaN(requestTime) || Math.abs(now - requestTime) > 300) {
  return [{ json: { verified: false, error: 'Timestamp expired or invalid (>5 min drift)' } }];
}

// Compute expected signature
const expectedSig = 'sha256=' + crypto
  .createHmac('sha256', secret)
  .update(rawBody, 'utf8')
  .digest('hex');

// Constant-time comparison
const sigBuffer = Buffer.from(signature);
const expectedBuffer = Buffer.from(expectedSig);

if (sigBuffer.length !== expectedBuffer.length || !crypto.timingSafeEqual(sigBuffer, expectedBuffer)) {
  return [{ json: { verified: false, error: 'HMAC signature mismatch' } }];
}

return [{ json: { verified: true, body: inputData.body } }];
